// Generated by Claude Sonnet 4.6

import { UnknownAction } from 'redux';

import {
  kubeconfigRefreshErrorAction,
  kubeconfigRefreshRequestAction,
  kubeconfigRefreshSuccessAction,
} from '@/store/Kubeconfig/actions';
import { KubeconfigState, reducer, unloadedState } from '@/store/Kubeconfig/reducer';

describe('Kubeconfig, reducer', () => {
  let initialState: KubeconfigState;

  beforeEach(() => {
    initialState = { ...unloadedState };
  });

  it('should return the initial state', () => {
    const unknownAction = { type: '@@INIT' } as UnknownAction;
    expect(reducer(undefined, unknownAction)).toEqual(unloadedState);
  });

  it('should handle kubeconfigRefreshRequestAction', () => {
    initialState.error = 'previous error';
    const action = kubeconfigRefreshRequestAction();
    const expectedState: KubeconfigState = {
      ...initialState,
      isLoading: true,
      error: undefined,
    };

    expect(reducer(initialState, action)).toEqual(expectedState);
  });

  it('should handle kubeconfigRefreshSuccessAction', () => {
    initialState.isLoading = true;

    const action = kubeconfigRefreshSuccessAction();
    const expectedState: KubeconfigState = {
      ...initialState,
      isLoading: false,
    };

    expect(reducer(initialState, action)).toEqual(expectedState);
  });

  it('should handle kubeconfigRefreshErrorAction', () => {
    initialState.isLoading = true;

    const error = 'Something went wrong';
    const action = kubeconfigRefreshErrorAction(error);
    const expectedState: KubeconfigState = {
      ...initialState,
      isLoading: false,
      error,
    };

    expect(reducer(initialState, action)).toEqual(expectedState);
  });

  it('should return the current state for unknown actions', () => {
    const unknownAction = { type: 'UNKNOWN_ACTION' } as UnknownAction;
    expect(reducer(initialState, unknownAction)).toEqual(initialState);
  });
});
